Toggle FPS display with a keyboard shortcut:
```typescript
class DebugControls extends cc.Layer {
    private _listener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.KEYBOARD,
            onKeyPressed: (keyCode: cc.KEY, event: cc.Event): void => {
                if (keyCode === cc.KEY.f1) {
                    const current = cc.director.isDisplayStats();
                    cc.director.setDisplayStats(!current);
                }
            }
        }, this);
    }

