Complete the following code to implement a scene stack manager:

```typescript
class SceneStackManager {
    // TODO: manage scene transitions with push/pop
    // TODO: support transitions
    // TODO: track current scene name for debugging
}
```

output:
```typescript
class SceneStackManager {
    private static _instance: SceneStackManager;
    private _sceneNames: string[] = [];
    private static readonly TRANSITION_DURATION = 0.4;

    static get instance(): SceneStackManager {
        if (!SceneStackManager._instance) {
            SceneStackManager._instance = new SceneStackManager();
        }
        return SceneStackManager._instance;
    }

    runScene(scene: cc.Scene, name: string, useTransition: boolean = true): void {
        this._sceneNames = [name];
        const target = useTransition
            ? new cc.TransitionFade(SceneStackManager.TRANSITION_DURATION, scene)
            : scene;
        cc.director.runScene(target);
        cc.log('Run scene:', name);
    }

    pushScene(scene: cc.Scene, name: string): void {
        this._sceneNames.push(name);
        cc.director.pushScene(scene);
        cc.log('Push scene:', name, '| Stack:', this._sceneNames.join(' > '));
    }

    popScene(): void {
        if (this._sceneNames.length <= 1) {
            cc.warn('Cannot pop root scene');
            return;
        }
        const popped = this._sceneNames.pop();
        cc.director.popScene();
        cc.log('Pop scene:', popped, '| Stack:', this._sceneNames.join(' > '));
    }

    popToRoot(): void {
        this._sceneNames = [this._sceneNames[0]];
        cc.director.popToRootScene();
        cc.log('Pop to root:', this._sceneNames[0]);
    }

    get currentSceneName(): string {
        return this._sceneNames[this._sceneNames.length - 1] || 'none';
    }

    get stackDepth(): number {
        return this._sceneNames.length;
    }
}

// Usage:
const mgr = SceneStackManager.instance;
mgr.runScene(new MenuScene(), 'menu');
mgr.pushScene(new SettingsScene(), 'settings');
mgr.popScene(); // back to menu
```

instruction:
Find and fix the bug in this scene transition code:

```typescript
class GameLayer extends cc.Layer {
    onGameOver(): void {
        const gameOverScene = new GameOverScene();
        cc.director.pushScene(gameOverScene);
        cc.director.purgeCachedData();
    }
}
```

output:
The bug is calling `purgeCachedData()` **after** `pushScene()`. When you push a scene, the current scene stays in memory on the stack. Purging cached data immediately after push will:

1. Destroy textures that the current (background) game scene still references
2. Possibly destroy textures needed by the new GameOverScene
3. Cause visual glitches or crashes when popping back

Fixed code:
```typescript
class GameLayer extends cc.Layer {
    onGameOver(): void {
        // Option 1: Push without purging (recommended for push/pop)
        const gameOverScene = new GameOverScene();
        cc.director.pushScene(gameOverScene);
        // Do NOT purge — the game scene is still on the stack
    }
}

// If you want to purge, use runScene instead (replaces, not pushes):
class GameLayer2 extends cc.Layer {
    onGameOver(): void {
        cc.director.purgeCachedData(); // purge BEFORE running new scene
        const gameOverScene = new GameOverScene();
        cc.director.runScene(new cc.TransitionFade(0.5, gameOverScene));
    }
}
```

Rule: only purge when using `runScene` (old scene is destroyed), never with `pushScene` (old scene stays alive).

instruction:
Review this code for issues:

```typescript
class LoadingScene extends cc.Scene {
    onEnter(): void {
        super.onEnter();
        cc.loader.load(['res/atlas.png', 'res/data.json'], () => {
            cc.director.runScene(new GameScene());
        });
        cc.director.setAnimationInterval(1 / 30);
    }
}
```

output:
Issues found:

1. **FPS set to 30 during loading.** Setting to 30 FPS in the loading scene makes sense for battery saving, but it's never restored to 60 FPS. The game scene will run at 30 FPS.

2. **No error handling in load callback.** If loading fails, the game silently transitions to GameScene with missing resources.

3. **No loading indicator.** The user sees nothing during loading.

4. **No transition.** Abrupt scene switch.

Fixed code:
```typescript
class LoadingScene extends cc.Scene {
    private static readonly GAME_FPS = 60;
    private static readonly LOADING_FPS = 30;

    onEnter(): void {
        super.onEnter();
        cc.director.setAnimationInterval(1 / LoadingScene.LOADING_FPS);

        // Show loading indicator
        const label = new cc.LabelTTF('Loading...', 'Arial', 24);
        const winSize = cc.director.getWinSize();
        label.setPosition(winSize.width / 2, winSize.height / 2);
        this.addChild(label);

        cc.loader.load(['res/atlas.png', 'res/data.json'], (err) => {
            if (err) {
                cc.error('Failed to load resources:', err);
                label.setString('Load failed! Tap to retry.');
                return;
            }
            // Restore FPS before transitioning
            cc.director.setAnimationInterval(1 / LoadingScene.GAME_FPS);
            cc.director.runScene(new cc.TransitionFade(0.3, new GameScene()));
        });
    }
}
```

Use the scheduler to control individual targets:

```typescript
const scheduler = cc.director.getScheduler();

// Pause a specific target (stops its scheduled callbacks)
scheduler.pauseTarget(enemyNode);

// Resume it
scheduler.resumeTarget(enemyNode);

// Check if paused
if (scheduler.isTargetPaused(enemyNode)) {
    cc.log('Enemy is paused');
}

// Pause ALL targets
scheduler.pauseAllTargets();

// Resume specific targets
scheduler.resumeTargets([enemyNode, bulletNode]);
```

Selective pause pattern (pause game but keep UI):
```typescript
class SelectivePause {
    private _pausedTargets: cc.Class[] = [];
    private _uiNodes: cc.Node[] = [];

    registerUI(node: cc.Node): void {
        this._uiNodes.push(node);
    }

    pauseGameplay(): void {
        const scheduler = cc.director.getScheduler();
        // Pause everything
        scheduler.pauseAllTargets();

        // Resume UI nodes
        for (const ui of this._uiNodes) {
            scheduler.resumeTarget(ui);
        }
    }

    resumeGameplay(): void {
        const scheduler = cc.director.getScheduler();
        scheduler.resumeTargets(this._pausedTargets);
    }
}
```

While `node.schedule()` is preferred, you can use the scheduler directly:

```typescript
const scheduler = cc.director.getScheduler();

// Schedule a repeating callback
scheduler.scheduleCallbackForTarget(
    myNode,                  // target
    (elapsed: number) => {   // callback
        cc.log('Elapsed:', elapsed);
    },
    1.0,                     // interval (seconds)
    cc.REPEAT_FOREVER,       // repeat count
    0,                       // delay before first call
    false                    // paused?
);

// Schedule update for a target
scheduler.scheduleUpdateForTarget(myNode, 0, false);

// Unschedule
scheduler.unscheduleCallbackForTarget(myNode, callbackRef);
scheduler.unscheduleUpdateForTarget(myNode);
scheduler.unscheduleAllCallbacksForTarget(myNode);
```

The node shorthand methods are usually cleaner:
```typescript
// Equivalent using node methods (preferred):
myNode.schedule((elapsed) => {
    cc.log('Elapsed:', elapsed);
}, 1.0);

myNode.scheduleUpdate();
myNode.unscheduleAllCallbacks();
```

Use the scheduler directly when you need to control pausing/resuming of specific targets or when working outside the node lifecycle.

