    if (err) {
        cc.error('Failed to load JSON:', err);
        return;
    }
    cc.log('Level data:', data);
    this.initLevel(data);
});

// Method 2: load + getRes (for batch loading)
cc.loader.load(['res/levels/level1.json', 'res/hero.png'], (err) => {
    if (err) return cc.error(err);

    // Retrieve cached JSON
    const levelData = cc.loader.getRes('res/levels/level1.json');
    cc.log('Level:', levelData);

    // Use the loaded resources
    this.buildLevel(levelData);
