```

output:
```typescript
enum TransitionType {
    FADE,
    NONE
}

class TransitionManager {
    private static readonly DEFAULT_DURATION = 0.5;
    private static _transitioning: boolean = false;

    static switchScene(
        scene: cc.Scene,
        type: TransitionType = TransitionType.FADE,
        duration: number = TransitionManager.DEFAULT_DURATION
    ): void {
        if (TransitionManager._transitioning) {
            cc.warn('Transition already in progress');
            return;
        }

        TransitionManager._transitioning = true;

        let target: cc.Scene;
        switch (type) {
            case TransitionType.FADE:
                target = new cc.TransitionFade(duration, scene);
                break;
            case TransitionType.NONE:
            default:
                target = scene;
                break;
        }

        // Schedule reset of transitioning flag
        const resetNode = new cc.Node();
        scene.addChild(resetNode);
        resetNode.scheduleOnce(() => {
            TransitionManager._transitioning = false;
            resetNode.removeFromParent();
        }, duration + 0.1);

        cc.director.runScene(target);
    }

    static pushScene(scene: cc.Scene): void {
        if (TransitionManager._transitioning) return;
        cc.director.pushScene(scene);
    }

    static popScene(): void {
        cc.director.popScene();
    }

    static popToRoot(): void {
        cc.director.popToRootScene();
    }

    static get isTransitioning(): boolean {
        return TransitionManager._transitioning;
    }
}

// Usage:
TransitionManager.switchScene(new GameScene(), TransitionType.FADE, 0.8);
```

instruction:
Find and fix the bug in this scheduler code:

```typescript
class EnemySpawner extends cc.Layer {
    onEnter(): void {
        super.onEnter();
        const scheduler = cc.director.getScheduler();
        scheduler.setTimeScale(0.5);
        this.schedule(this.spawnEnemy, 2.0);
    }

    spawnEnemy(): void {
        cc.log('Spawning enemy');
    }
}
```

output:
The bug is that `setTimeScale(0.5)` is set **globally** in a layer's `onEnter`. This halves the speed of the **entire game**, not just enemy spawning. Every node, action, and scheduler callback across all layers will run at half speed.

Also, the time scale is never restored.

Fixed code:
```typescript
class EnemySpawner extends cc.Layer {
    private static readonly SPAWN_INTERVAL = 2.0;

    onEnter(): void {
        super.onEnter();
        // Don't set global time scale for local behavior!
        // Instead, just adjust the spawn interval directly:
        this.schedule(this.spawnEnemy, EnemySpawner.SPAWN_INTERVAL);
    }

    spawnEnemy(): void {
        cc.log('Spawning enemy');
    }

    onExit(): void {
        this.unschedule(this.spawnEnemy);
        super.onExit();
    }
}
```

If you truly need slow motion, save and restore:
