        this._savedScale = scheduler.getTimeScale();
        scheduler.setTimeScale(0.5);
    }

    deactivate(): void {
        cc.director.getScheduler().setTimeScale(this._savedScale);
    }
}
```

While `node.runAction()` is preferred, you can use `addAction` directly:

```typescript
cc.director.getActionManager().addAction(
    action: cc.Action,
    target: cc.Node,
    paused: boolean
): void
```

Example:
```typescript
const mgr = cc.director.getActionManager();

// Add an action manually
const moveAction = cc.moveTo(1.0, cc.p(300, 200));
mgr.addAction(moveAction, mySprite, false);

// Add a paused action (won't run until resumed)
const rotateAction = cc.rotateBy(2.0, 360);
mgr.addAction(rotateAction, mySprite, true);

// Resume to start the paused action
mgr.resumeTarget(mySprite);
```

This is equivalent to `mySprite.runAction(moveAction)` but gives you control over the initial paused state.

Useful for batch action management:
