Practical UI layout:
```typescript
class UILayout {
    private _origin: cc.Point;
    private _size: cc.Size;

    constructor() {
        this._origin = cc.director.getVisibleOrigin();
        this._size = cc.director.getVisibleSize();
    }

    topLeft(): cc.Point {
        return cc.p(this._origin.x, this._origin.y + this._size.height);
    }

    topRight(): cc.Point {
        return cc.p(this._origin.x + this._size.width, this._origin.y + this._size.height);
    }

    bottomLeft(): cc.Point {
        return cc.p(this._origin.x, this._origin.y);
    }

    bottomRight(): cc.Point {
        return cc.p(this._origin.x + this._size.width, this._origin.y);
    }

    center(): cc.Point {
        return cc.p(
            this._origin.x + this._size.width / 2,
            this._origin.y + this._size.height / 2
        );
    }
}
```

Difference: `getWinSize()` returns the design resolution. `getVisibleSize()` + `getVisibleOrigin()` return the area actually visible on screen after resolution policy is applied.

Track loading progress using the loader callback:

```typescript
class LoadingScene extends cc.Scene {
    private _progressBar: cc.Sprite;
    private _label: cc.LabelTTF;

    onEnter(): void {
        super.onEnter();
        const winSize = cc.director.getWinSize();

        // Progress bar background
        const bg = new cc.LayerColor(cc.color(50, 50, 50));
        this.addChild(bg);

        this._label = new cc.LabelTTF('Loading... 0%', 'Arial', 20);
        this._label.setPosition(winSize.width / 2, winSize.height / 2 + 30);
        this.addChild(this._label);

        this._progressBar = new cc.Sprite('res/ui/progress_fill.png');
        this._progressBar.setAnchorPoint(0, 0.5);
        this._progressBar.setPosition(winSize.width * 0.2, winSize.height / 2 - 20);
        this._progressBar.setScaleX(0);
        this.addChild(this._progressBar);

        this.startLoading();
    }

    private startLoading(): void {
        const resources = [
            'res/game/atlas.png',
            'res/game/atlas.plist',
            'res/game/level.json',
            'res/audio/bgm.mp3'
        ];

        let loaded = 0;
        const total = resources.length;

        cc.loader.load(resources, (err) => {
            if (err) {
                cc.error('Loading failed:', err);
                this._label.setString('Load failed!');
                return;
            }
            loaded++;
            const progress = loaded / total;
            this._progressBar.setScaleX(progress);
            this._label.setString('Loading... ' + Math.round(progress * 100) + '%');

            if (loaded >= total) {
                this.onLoadComplete();
            }
        });
    }

    private onLoadComplete(): void {
        this._label.setString('Complete!');
        this.scheduleOnce(() => {
            cc.director.runScene(new cc.TransitionFade(0.5, new GameScene()));
        }, 0.5);
    }
}
```

