Build a level manager that loads resources before transitioning:

```typescript
class LevelManager {
    private static _currentLevel: number = 0;

    static loadLevel(levelNum: number): void {
        const levelPath = 'res/levels/level' + levelNum + '.json';
        const assets = [
            levelPath,
            'res/levels/level' + levelNum + '_bg.png'
        ];

        // Show loading scene
        const loading = new LoadingScene();
        cc.director.runScene(loading);

        cc.loader.load(assets, (err) => {
            if (err) {
                cc.error('Failed to load level', levelNum);
                return;
            }

            const levelData = cc.loader.getRes(levelPath);
            LevelManager._currentLevel = levelNum;

            const gameScene = new GameScene();
            gameScene.setLevelData(levelData);
            cc.director.runScene(new cc.TransitionFade(0.5, gameScene));
        });
    }

    static nextLevel(): void {
        // Release current level resources
        cc.loader.release('res/levels/level' + LevelManager._currentLevel + '.json');
        cc.loader.release('res/levels/level' + LevelManager._currentLevel + '_bg.png');

        LevelManager.loadLevel(LevelManager._currentLevel + 1);
    }

    static restartLevel(): void {
        LevelManager.loadLevel(LevelManager._currentLevel);
    }

    static get currentLevel(): number {
        return LevelManager._currentLevel;
    }
}

// Usage:
LevelManager.loadLevel(1);
// After beating level:
LevelManager.nextLevel();
```

instruction:
Find and fix the bug in this action manager code:

```typescript
class GameController {
    private _pausedTargets: cc.Node[];

    pauseGame(): void {
        this._pausedTargets = cc.director.getActionManager().pauseAllRunningActions();
        cc.director.getScheduler().pauseAllTargets();
    }

    resumeGame(): void {
        cc.director.getActionManager().resumeTargets(this._pausedTargets);
    }
}
```

output:
Two bugs:

**Bug 1: Scheduler targets not resumed.** `pauseGame` pauses both actions and scheduler, but `resumeGame` only resumes actions. All scheduled callbacks remain paused.

**Bug 2: `_pausedTargets` not initialized.** If `resumeGame` is called before `pauseGame`, `_pausedTargets` is `undefined`, causing a crash.

Fixed code:
```typescript
class GameController {
    private _pausedActionTargets: cc.Node[] = [];
    private _schedulerPaused: boolean = false;

    pauseGame(): void {
        this._pausedActionTargets = cc.director.getActionManager().pauseAllRunningActions();
        cc.director.getScheduler().pauseAllTargets();
        this._schedulerPaused = true;
        cc.log('Game paused');
    }

    resumeGame(): void {
        // Resume actions
        if (this._pausedActionTargets.length > 0) {
            cc.director.getActionManager().resumeTargets(this._pausedActionTargets);
            this._pausedActionTargets = [];
        }

        // Resume scheduler targets too
        if (this._schedulerPaused) {
            // pauseAllTargets returns paused set, but we didn't store it.
            // Better approach: use cc.director.resume() for global resume
            cc.director.resume();
            this._schedulerPaused = false;
        }

        cc.log('Game resumed');
    }
}
```

Alternatively, use `cc.director.pause()` / `cc.director.resume()` which handle both actions and scheduler together.

