```

Scene transition with selective resource management:
```typescript
class ResourceManager {
    private static _levelResources: Map<number, string[]> = new Map();

    static registerLevelResources(level: number, resources: string[]): void {
        ResourceManager._levelResources.set(level, resources);
    }

    static loadLevel(level: number, callback: () => void): void {
        const resources = ResourceManager._levelResources.get(level);
        if (!resources) {
            cc.error('No resources registered for level', level);
            return;
        }
        cc.loader.load(resources, (err) => {
            if (err) {
                cc.error('Failed to load level', level, err);
                return;
            }
            callback();
        });
    }

    static releaseLevel(level: number): void {
        const resources = ResourceManager._levelResources.get(level);
        if (!resources) return;
        for (const res of resources) {
            cc.loader.release(res);
        }
        cc.log('Released resources for level', level);
    }

    static transitionLevel(from: number, to: number): void {
        ResourceManager.loadLevel(to, () => {
            ResourceManager.releaseLevel(from);
            cc.director.runScene(new cc.TransitionFade(0.5, new GameScene()));
        });
    }
}

// Register resources per level
ResourceManager.registerLevelResources(1, ['res/l1/bg.png', 'res/l1/tileset.png']);
ResourceManager.registerLevelResources(2, ['res/l2/bg.png', 'res/l2/tileset.png']);
```

instruction:
Review this scene lifecycle code and identify issues:

```typescript
class GameScene extends cc.Scene {
    private _gameLayer: GameLayer;

    constructor() {
        super();
        this._gameLayer = new GameLayer();
        this.addChild(this._gameLayer);
        this.startGame();
    }

    startGame(): void {
        const winSize = cc.director.getWinSize();
        this._gameLayer.setup(winSize);
    }
}
```

output:
Issues found:

1. **Initialization in constructor instead of onEnter.** In Cocos2d-x, nodes aren't fully initialized in the constructor. The scene isn't attached to the director yet, so `cc.director.getWinSize()` may work but `addChild` during construction can cause ordering issues.

2. **`startGame` called in constructor.** The layer's `onEnter` hasn't been called yet, so any initialization the layer does in `onEnter` hasn't happened. `setup` will operate on an uninitialized layer.

3. **No `super.onEnter()` call visible.** If `onEnter` is overridden elsewhere, it must call `super.onEnter()`.

Fixed code:
```typescript
class GameScene extends cc.Scene {
    private _gameLayer: GameLayer;

    onEnter(): void {
        super.onEnter(); // always call super first

        this._gameLayer = new GameLayer();
        this.addChild(this._gameLayer);

        // Now the layer's onEnter has been called
        const winSize = cc.director.getWinSize();
        this._gameLayer.setup(winSize);
        this.startGame();
    }

    private startGame(): void {
        cc.log('Game started');
    }
}
```

Rule: always do node creation and scene setup in `onEnter()`, not in the constructor. This ensures the scene graph is properly connected.

Use the scheduler for frame-by-frame updates and timed events:

```typescript
class GameLoop extends cc.Layer {
    private _elapsed: number = 0;
    private _fixedTimeStep: number = 1 / 60;
    private _accumulator: number = 0;

    onEnter(): void {
        super.onEnter();
        this.scheduleUpdate();
    }

    update(dt: number): void {
        // Cap delta time to prevent spiral of death
        const cappedDt = Math.min(dt, 0.1);

        // Fixed timestep for physics
        this._accumulator += cappedDt;
        while (this._accumulator >= this._fixedTimeStep) {
            this.fixedUpdate(this._fixedTimeStep);
            this._accumulator -= this._fixedTimeStep;
        }

        // Variable timestep for rendering/interpolation
        this.variableUpdate(cappedDt);

        this._elapsed += cappedDt;
    }

    private fixedUpdate(dt: number): void {
        // Physics, collision detection
        this.updatePhysics(dt);
        this.checkCollisions();
    }

    private variableUpdate(dt: number): void {
        // Visual updates, particle effects
        this.updateAnimations(dt);
        this.updateCamera(dt);
    }

    // Timed events using schedule
    private startTimedEvents(): void {
        this.schedule(this.spawnEnemy, 3.0);
        this.schedule(this.updateDifficulty, 30.0);
        this.scheduleOnce(this.showBoss, 120.0);
    }
}
```

The fixed timestep loop ensures physics is deterministic regardless of frame rate. Use `cc.director.getDeltaTime()` if you need dt outside of the update callback.

`cc.loader.getXMLHttpRequest()` returns a cross-platform XMLHttpRequest:

```typescript
const xhr = cc.loader.getXMLHttpRequest();
xhr.open('GET', 'https://api.example.com/scores', true);
xhr.setRequestHeader('Content-Type', 'application/json');

xhr.onreadystatechange = function() {
    if (xhr.readyState === 4) {
        if (xhr.status === 200) {
            const data = JSON.parse(xhr.responseText);
            cc.log('Scores received:', data);
        } else {
            cc.error('Request failed:', xhr.status);
        }
    }
};

xhr.send();
```

POST example:
```typescript
function postScore(score: number, callback: (success: boolean) => void): void {
    const xhr = cc.loader.getXMLHttpRequest();
    xhr.open('POST', 'https://api.example.com/scores', true);
    xhr.setRequestHeader('Content-Type', 'application/json');

    xhr.onreadystatechange = function() {
        if (xhr.readyState === 4) {
            callback(xhr.status === 200);
        }
    };

    xhr.send(JSON.stringify({ score: score, timestamp: Date.now() }));
}
```

Using `cc.loader.getXMLHttpRequest()` instead of `new XMLHttpRequest()` ensures compatibility across native (JSB) and browser environments.

