Build a startup sequence that coordinates all systems:

```typescript
class GameBootstrap {
    static start(): void {
        // Step 1: Configure display
        cc.director.setDisplayStats(false);
        cc.director.setAnimationInterval(1 / 60);

        // Step 2: Run splash/loading scene
        cc.director.runScene(new SplashScene());
    }
}

class SplashScene extends cc.Scene {
    onEnter(): void {
        super.onEnter();
        const winSize = cc.director.getWinSize();

        // Show splash
        const label = new cc.LabelTTF('Loading...', 'Arial', 24);
        label.setPosition(winSize.width / 2, winSize.height / 2);
        this.addChild(label);

        // Load core assets
        const coreAssets = [
            'res/ui/atlas.png',
            'res/ui/atlas.plist',
            'res/config.json'
        ];

        cc.loader.load(coreAssets, (err) => {
            if (err) {
                cc.error('Boot failed:', err);
                return;
            }
            this.onAssetsLoaded();
        });
    }

    private onAssetsLoaded(): void {
        // Register global event listeners
        cc.eventManager.addCustomListener('game:fatal_error', (event: cc.Event) => {
            const data = event.getUserData<{ message: string }>();
            cc.error('Fatal:', data.message);
        });

        // Load config
        const config = cc.loader.getRes('res/config.json');

        // Transition to menu
        this.scheduleOnce(() => {
            cc.director.runScene(new cc.TransitionFade(0.5, new MenuScene()));
        }, 0.5);
    }
}
