Load resources during a transition scene, then swap:

```typescript
class SmartTransition {
    static go(
        targetFactory: () => cc.Scene,
        resources: string[]
    ): void {
        // Create an intermediate loading scene
        const loadingScene = new cc.Scene();
        const winSize = cc.director.getWinSize();

        const overlay = new cc.LayerColor(cc.color(0, 0, 0));
        loadingScene.addChild(overlay);

        const label = new cc.LabelTTF('Loading...', 'Arial', 18);
        label.setPosition(winSize.width / 2, winSize.height / 2);
        loadingScene.addChild(label);

        // Fade to loading scene
        cc.director.runScene(new cc.TransitionFade(0.3, loadingScene));

        // Start loading after transition completes
        const waitNode = new cc.Node();
        loadingScene.addChild(waitNode);
        waitNode.scheduleOnce(() => {
            if (resources.length === 0) {
                SmartTransition.finalize(targetFactory);
                return;
            }
            cc.loader.load(resources, (err) => {
                if (err) cc.error('Load error:', err);
                SmartTransition.finalize(targetFactory);
            });
        }, 0.4); // wait for fade-in
    }

    private static finalize(factory: () => cc.Scene): void {
        const target = factory();
        cc.director.runScene(new cc.TransitionFade(0.3, target));
    }
}

// Usage:
SmartTransition.go(
    () => new GameScene(),
    ['res/game/atlas.png', 'res/game/level.json']
);
```

